#include <stdio.h>
int main() {
    int a, b, c, d, x, y, i, j;
    scanf("%d%d%d%d", &a,&b,&c,&d);
    int max = a;
    if(c<max)
        max = c;
    if(d<max)
        max = d;

    x = 256*max;

    a = a - max;
    c = c - max;
    d = d - max;

    max = a;
    if(b<max)
        max = b;

    x = x + 32*max;

    printf("%d\n", x);
}

